class Solution(object):
    def spiralOrder(self, matrix):
        """
        :type matrix: List[List[int]]
        :rtype: List[int]
        """
        if not matrix:
            return []

        result = []
        while matrix:
            # Append the first row
            result += matrix.pop(0)
            # Rotate the remaining matrix 90 degrees clockwise
            if matrix and matrix[0]:
                for row in matrix:
                    result.append(row.pop())
            # Append the last row if it exists
            if matrix:
                result += matrix.pop()[::-1]
            # Rotate the remaining matrix 90 degrees clockwise
            if matrix and matrix[0]:
                for row in matrix[::-1]:
                    result.append(row.pop(0))

        return result

