class Solution(object):
    def summaryRanges(self, nums):
        """
        :type nums: List[int]
        :rtype: List[str]
        """
        if not nums:
            return []

        result = []
        start = end = nums[0]

        for i in range(1, len(nums)):
            if nums[i] != end + 1:
                if start == end:
                    result.append(str(start))
                else:
                    result.append(f"{start}->{end}")
                start = end = nums[i]
            else:
                end = nums[i]

        if start == end:
            result.append(str(start))
        else:
            result.append(f"{start}->{end}")

        return result

