class Solution(object):
    def numDistinct(self, s, t):
        """
        :type s: str
        :type t: str
        :rtype: int
        """
        dp = [0] * (len(t) + 1)
        dp[0] = 1

        for char in s:
            for j in range(len(t), 0, -1):
                if t[j-1] == char:
                    dp[j] += dp[j-1]

        return dp[len(t)]

first-missing-positive.solution:
class Solution(object):
    def firstMissingPositive(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        n = len(nums)
        has_one = False

        # Check if 1 is present in the array
        for num in nums:
            if num == 1:
                has_one = True
                break
        if not has_one:
            return 1

        # Replace negative numbers, zeros, and numbers larger than n with 1s
        for i in range(n):
            if nums[i] <= 0 or nums[i] > n:
                nums[i] = 1

        # Use index as a hash key and number sign as a presence detector
        for i in range(n):
            index = abs(nums[i]) - 1
            nums[index] = -abs(nums[index])

        # Find the first cell which isn't negative (means its index + 1 is missing)
        for i in range(n):
            if nums[i] > 0:
                return i + 1

        # If all numbers from 1 to n are present, then the missing number is n + 1
        return n + 1

