class Solution(object):
    def addOperators(self, num, target):
        """
        :type num: str
        :type target: int
        :rtype: List[str]
        """
        def dfs(index, path, res, last, prev):
            if index == len(num):
                if res == target:
                    result.append(path)
                return

            for i in range(index, len(num)):
                curr = int(num[index:i+1])
                if index == 0:
                    dfs(i+1, path + str(curr), curr, curr, curr)
                else:
                    dfs(i+1, path + '+' + str(curr), res + curr, curr, curr)
                    dfs(i+1, path + '-' + str(curr), res - curr, -curr, curr)
                    dfs(i+1, path + '*' + str(curr), res - prev + prev * curr, prev * curr, curr)

        result = []
        dfs(0, "", 0, 0, 0)
        return result

