class Solution(object):
    def toHex(self, num):
        """
        :type num: int
        :rtype: str
        """
        if num == 0:
            return "0"
        hex_chars = "0123456789abcdef"
        result = ""
        if num < 0:
            num += 2**32
        while num > 0:
            result = hex_chars[num % 16] + result
            num /= 16
        return result

first-unique-character-in-a-string.solution:
class Solution(object):
    def firstUniqChar(self, s):
        """
        :type s: str
        :rtype: int
        """
        from collections import OrderedDict

        # Using OrderedDict to remember the order of characters
        char_count = OrderedDict()

        # Counting each character's occurrence
        for char in s:
            if char in char_count:
                char_count[char] += 1
            else:
                char_count[char] = 1

        # Finding the first character with a count of 1
        for char, count in char_count.items():
            if count == 1:
                return s.index(char)

        # If no unique character is found
        return -1

