class Solution(object):
    def calculate(self, s):
        """
        :type s: str
        :rtype: int
        """
        stack = []
        num = 0
        sign = '+'

        for i in range(len(s)):
            if s[i].isdigit():
                num = num * 10 + int(s[i])

            if s[i] == '+' or s[i] == '-' or s[i] == ')' or i == len(s) - 1:
                if sign == '+':
                    stack.append(num)
                elif sign == '-':
                    stack.append(-num)

                if s[i] == ')':
                    temp = 0
                    while stack and stack[-1] != '(':
                        temp += stack.pop()
                    if stack and stack[-1] == '(':
                        stack.pop()
                    stack.append(temp)

                num = 0
                sign = s[i]

        return sum(stack)

