class Solution(object):
    def minSwapsCouples(self, row):
        """
        :type row: List[int]
        :rtype: int
        """
        pos = {x:i for i,x in enumerate(row)}
        count = 0
        for i in range(0, len(row), 2):
            if row[i] // 2 != row[i+1] // 2:
                j = pos[row[i] ^ 1]
                row[i+1], row[j] = row[j], row[i+1]
                pos[row[i+1]] = i + 1
                pos[row[j]] = j
                count += 1
        return count

