class Solution(object):
    def shortestPalindrome(self, s):
        """
        :type s: str
        :rtype: str
        """
        if not s:
            return ""

        i = 0
        for j in range(len(s) - 1, -1, -1):
            if s[i] == s[j]:
                i += 1

        if i == len(s):
            return s

        suffix = s[i:]
        reversed_suffix = suffix[::-1]
        prefix = self.shortestPalindrome(s[:i])

        return reversed_suffix + prefix + s

