from heapq import heappop, heappush
from collections import deque

class Solution(object):
    def cutOffTree(self, forest):
        """
        :type forest: List[List[int]]
        :rtype: int
        """
        if not forest or not forest[0]:
            return -1

        rows, cols = len(forest), len(forest[0])
        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]

        # Extract positions and heights of all trees
        trees = []
        for i in range(rows):
            for j in range(cols):
                if forest[i][j] > 1:
                    trees.append((forest[i][j], i, j))

        # Sort trees by height
        trees.sort()

        start_x, start_y = 0, 0
        total_steps = 0

        for _, target_x, target_y in trees:
            steps = self.bfs_shortest_path(forest, start_x, start_y, target_x, target_y)
            if steps == -1:
                return -1
            total_steps += steps
            start_x, start_y = target_x, target_y

        return total_steps

    def bfs_shortest_path(self, forest, start_x, start_y, target_x, target_y):
        rows, cols = len(forest), len(forest[0])
        visited = set()
        queue = deque([(start_x, start_y, 0)])

        while queue:
            x, y, steps = queue.popleft()
            if (x, y) in visited:
                continue
            visited.add((x, y))

            if x == target_x and y == target_y:
                return steps

            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nx, ny = x + dx, y + dy
                if 0 <= nx < rows and 0 <= ny < cols and forest[nx][ny] != 0 and (nx, ny) not in visited:
                    queue.append((nx, ny, steps + 1))

        return -1

