class Solution(object):
    def multiply(self, num1, num2):
        """
        :type num1: str
        :type num2: str
        :rtype: str
        """
        if num1 == "0" or num2 == "0":
            return "0"

        result = [0] * (len(num1) + len(num2))
        for i in range(len(num1)-1, -1, -1):
            for j in range(len(num2)-1, -1, -1):
                mul = int(num1[i]) * int(num2[j])
                p1, p2 = i + j, i + j + 1
                sum_ = mul + result[p2]

                result[p1] += sum_ // 10
                result[p2] = sum_ % 10

        res = []
        for n in result:
            if not res and n == 0:
                continue
            res.append(str(n))
        return "".join(res)

