remove-invalid-parentheses.solution:
from collections import deque

class Solution(object):
    def removeInvalidParentheses(self, s):
        """
        :type s: str
        :rtype: List[str]
        """
        if not s:
            return [""]

        # Function to check if a string has balanced parentheses
        def is_valid(s):
            balance = 0
            for char in s:
                if char == '(':
                    balance += 1
                elif char == ')':
                    balance -= 1
                if balance < 0:
                    return False
            return balance == 0

        queue = deque([s])
        visited = {s}
        result = []

        while queue:
            current = queue.popleft()

            if is_valid(current):
                result.append(current)
                continue

            if len(result) > 0:
                break  # No need to go further if we have found valid strings at this level

            for i in range(len(current)):
                if current[i] != '(' and current[i] != ')':
                    continue
                next_str = current[:i] + current[i+1:]
                if next_str not in visited:
                    visited.add(next_str)
                    queue.append(next_str)

        return result

preimage-size-of-factorial-zeroes-functi.solution:
class Solution(object):
    def preimageSizeFZF(self, k):
        """
        :type k: int
        :rtype: int
        """
        if k == 0:
            return 5

        # Function to count trailing zeros in factorial
        def trailingZeros(n):
            count = 0
            power = 5
            while n >= power:
                count += n // power
                power *= 5
            return count

        # Binary search for the smallest x such that trailingZeros(x) >= k
        left, right = 0, 5 * (k + 1)
        while left < right:
            mid = (left + right) // 2
            if trailingZeros(mid) < k:
                left = mid + 1
            else:
                right = mid

        # Check if there are exactly k trailing zeros for x in [left-4, left+4]
        result = 0
        for i in range(left - 4, left + 5):
            if trailingZeros(i) == k:
                result += 1

        return result

