class Solution(object):
    def palindromePairs(self, words):
        """
        :type words: List[str]
        :rtype: List[List[int]]
        """
        word_dict = {word: i for i, word in enumerate(words)}
        result = []

        for word, k in word_dict.items():
            n = len(word)
            for j in range(n+1):
                prefix = word[:j]
                suffix = word[j:]

                if prefix == prefix[::-1]:
                    back = suffix[::-1]
                    if back != word and back in word_dict:
                        result.append([word_dict[back], k])

                if j != n and suffix == suffix[::-1]:
                    back = prefix[::-1]
                    if back != word and back in word_dict:
                        result.append([k, word_dict[back]])

        return result

