from collections import deque

class Solution(object):
    def containVirus(self, isInfected):
        """
        :type isInfected: List[List[int]]
        :rtype: int
        """
        def spread(i, j, visited, walls_to_build, regions):
            queue = deque([(i, j)])
            region = []
            while queue:
                x, y = queue.popleft()
                if (x, y) in visited:
                    continue
                visited.add((x, y))
                region.append((x, y))
                for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < len(isInfected) and 0 <= ny < len(isInfected[0]):
                        if isInfected[nx][ny] == 1:
                            walls_to_build += spread(nx, ny, visited, walls_to_build, regions)
                        elif isInfected[nx][ny] == 0:
                            walls_to_build += 1
                            queue.append((nx, ny))
            regions.append(region)
            return walls_to_build

        def build_walls(regions):
            max_uninfected = 0
            target_region_index = -1
            for i, region in enumerate(regions):
                uninfected = sum(1 for r, c in region if isInfected[r][c] == 0)
                if uninfected > max_uninfected:
                    max_uninfected = uninfected
                    target_region_index = i
            if target_region_index == -1:
                return False
            for r, c in regions[target_region_index]:
                isInfected[r][c] = -1
            return True

        days = 0
        while True:
            visited = set()
            walls_to_build = 0
            regions = []
            for i in range(len(isInfected)):
                for j in range(len(isInfected[0])):
                    if isInfected[i][j] == 1 and (i, j) not in visited:
                        walls_to_build += spread(i, j, visited, walls_to_build, regions)

            if not build_walls(regions):
                break

            days += walls_to_build

        return days

