        """
        :type n: int
        :rtype: int
        """
        if n < 1:
            return 0

        str_n = str(n)
        length = len(str_n)
        first_digit = int(str_n[0])
        remainder = int(str_n[1:])

        if first_digit == 0:
            return self.countDigitOne(remainder)
        elif first_digit == 1:
            return self.countDigitOne(remainder) + remainder + 1 + self.countDigitOne(10**(length-2)-1)
        else:
            return first_digit * (length - 1) * 10 ** (length - 2) + 10 ** (length - 1) + self.countDigitOne(remainder)

