class Solution(object):
    def medianSlidingWindow(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: List[float]
        """
        result = []
        window = SortedList()

        for i in range(len(nums)):
            window.add(nums[i])
            if len(window) > k:
                window.remove(nums[i-k])

            if len(window) == k:
                if k % 2 == 1:
                    result.append(float(window[k//2]))
                else:
                    result.append((window[k//2 - 1] + window[k//2]) / 2.0)

        return result

