from itertools import permutations

class Solution(object):
    def judgePoint24(self, nums):
        """
        :type nums: List[int]
        :rtype: bool
        """
        # Helper function to check if three numbers can be combined to get 24
        def helper(a, b, c):
            return any(abs(eval(f"{a}{op}{b}{op}{c}")) < 1e-6 for op in "+-*/")

        # Generate all permutations of the input numbers
        for perm in permutations(nums):
            # Try all combinations of pairs of operations
            for ops in permutations("+-*/", 3):
                # Evaluate the expression in different possible orders
                if eval(f"({perm[0]}{ops[0]}{perm[1]}){ops[1]}({perm[2]}{ops[2]}{perm[3]})") < 24.0001 and abs(eval(f"({perm[0]}{ops[0]}{perm[1]}){ops[1]}({perm[2]}{ops[2]}{perm[3]})") - 24) < 1e-6 or \
                   eval(f"{perm[0]}{ops[0]}(({perm[1]}{ops[1]}{perm[2]}){ops[2]}{perm[3]})") < 24.0001 and abs(eval(f"{perm[0]}{ops[0]}(({perm[1]}{ops[1]}{perm[2]}){ops[2]}{perm[3]})") - 24) < 1e-6 or \
                   eval(f"(([{perm[0]}{ops[0]}{perm[1]}]){ops[1]}{perm[2]}){ops[2]}{perm[3]}") < 24.0001 and abs(eval(f"(([{perm[0]}{ops[0]}{perm[1]}]){ops[1]}{perm[2]}){ops[2]}{perm[3]}") - 24) < 1e-6:
                    return True
                if helper(perm[0], perm[1], perm[2]) and helper(helper(perm[0], perm[1], perm[2]), perm[3]):
                    return True
                if helper(perm[0], perm[1], perm[3]) and helper(helper(perm[0], perm[1], perm[3]), perm[2]):
                    return True
                if helper(perm[0], perm[2], perm[3]) and helper(helper(perm[0], perm[2], perm[3]), perm[1]):
                    return True
                if helper(perm[1], perm[2], perm[3]) and helper(helper(perm[1], perm[2], perm[3]), perm[0]):
                    return True
        return False

