        dp[-1][-1] = True

        for i in range(len(s), -1, -1):
            for j in range(len(p) - 1, -1, -1):
                if p[j] == '*':
                    dp[i][j] = dp[i+1][j] or (i < len(s) and dp[i][j+1])
                elif i < len(s) and (p[j] == '?' or s[i] == p[j]):
