from functools import lru_cache

class Solution(object):
    def kInversePairs(self, n, k):
        """
        :type n: int
        :type k: int
        :rtype: int
        """
        MOD = 10**9 + 7

        @lru_cache(None)
        def dp(n, k):
            if n == 0:
                return 0
            if k == 0:
                return 1
            if k < 0:
                return 0
            return (dp(n, k - 1) + dp(n - 1, k) - dp(n - 1, k - n)) % MOD

        return dp(n, k)

redundant-connection-ii.solution:
class Solution(object):
    def findRedundantDirectedConnection(self, edges):
        """
        :type edges: List[List[int]]
        :rtype: List[int]
        """
        parent = {}
        candidate = None

        def find(x):
            if x != parent[x]:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            parent.setdefault(x, x)
            parent.setdefault(y, y)
            parent[find(x)] = find(y)

        # First pass to detect cycles and identify nodes with two parents
        for u, v in edges:
            if v in parent:
                candidate = [parent[v], v], [u, v]
                continue
            union(u, v)

        # Second pass to determine if we need to remove a redundant edge
        for u, v in reversed(edges):
            if u == candidate[0][0] and v == candidate[0][1]:
                continue
            if find(u) == find(v):
                return candidate[1] if candidate else [u, v]
            union(u, v)

        return candidate[1]

