class Solution(object):
    def cherryPickup(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        n = len(grid)
        dp = [[[float('-inf')] * n for _ in range(n)] for _ in range(n)]
        dp[0][0][0] = grid[0][0]

        for i in range(n):
            for j in range(n):
                for k in range(n):
                    l = i + j - k
                    if not (0 <= i < n and 0 <= j < n and 0 <= k < n and 0 <= l < n):
                        continue
                    if grid[i][j] == -1 or grid[k][l] == -1:
                        continue
                    current = grid[i][j] + (grid[k][l] if i != k else 0)
                    dp[i][j][k] = max(dp[i-1][j][k], dp[i][j-1][k], dp[i-1][j-1][k], dp[i][j][k-1]) + current

        result = dp[-1][-1][-1]
        return result if result > float('-inf') else 0

