            sign = 1

        x = abs(x)
        rev = 0

        while x != 0:
            pop = x % 10
            x /= 10

            # Check for overflow
            if rev > (2**31 - 1) / 10 or (rev == (2**31 - 1) / 10 and pop > 7):
                return 0
            if rev < -(2**31) / 10 or (rev == -(2**31) / 10 and pop < -8):
                return 0

            rev = rev * 10 + pop

        return sign * rev

