class Solution(object):
    def canCross(self, stones):
        """
        :type stones: List[int]
        :rtype: bool
        """
        stone_set = set(stones)
        memo = {}

        def dp(position, step):
            if position == stones[-1]:
                return True
            if (position, step) in memo:
                return memo[(position, step)]
            for next_step in range(step-1, step+2):
                if next_step > 0 and position + next_step in stone_set:
                    if dp(position + next_step, next_step):
                        memo[(position, step)] = True
                        return True
            memo[(position, step)] = False
            return False

        return dp(0, 0)

