            return 1

        # Initialize a list to store the number of unique BSTs for each count of nodes
        dp = [0] * (n + 1)
        dp[0], dp[1] = 1, 1

        # Fill the dp array using the formula for Catalan numbers
        for i in range(2, n + 1):
            for j in range(1, i + 1):
                dp[i] += dp[j - 1] * dp[i - j]

        return dp[n]

