class Solution(object):
    def minStickers(self, stickers, target):
        """
        :type stickers: List[str]
        :type target: str
        :rtype: int
        """
        # Create a dictionary to store the minimum stickers needed for each prefix of the target
        dp = {(): 0}

        # Iterate over each character in the target
        for char in target:
            new_dp = dp.copy()
            # Try using each sticker
            for sticker in stickers:
                if sticker[0] == char:
                    remaining = tuple(sorted((Counter(sticker) + Counter(target)) - (2 * Counter(char))))
                    if remaining not in new_dp or new_dp[remaining] > dp[tuple(sorted(Counter(target) - Counter(char)))] + 1:
                        new_dp[remaining] = dp[tuple(sorted(Counter(target) - Counter(char)))] + 1
            dp = new_dp

        # Return the result for the full target or -1 if not possible
        return dp.get(tuple(sorted(target)), -1)

