class Solution(object):
    def strangePrinter(self, s):
        """
        :type s: str
        :rtype: int
        """
        n = len(s)
        dp = [[float('inf')] * n for _ in range(n)]

        # Base case: single character cost is 1
        for i in range(n):
            dp[i][i] = 1

        # Fill the dp table
        for length in range(2, n + 1):
            for start in range(n - length + 1):
                end = start + length - 1
                dp[start][end] = dp[start + 1][end] + 1  # Initial cost if we don't merge anything

                for k in range(start + 1, end + 1):
                    if s[k] == s[start]:
                        dp[start][end] = min(dp[start][end], dp[start][k - 1] + dp[k + 1][end])

        return dp[0][n - 1]

