from collections import defaultdict, deque

class Solution(object):
    def findLadders(self, beginWord, endWord, wordList):
        """
        :type beginWord: str
        :type endWord: str
        :type wordList: List[str]
        :rtype: List[List[str]]
        """
        word_set = set(wordList)
        if endWord not in word_set:
            return []

        word_dict = defaultdict(list)
        length = len(beginWord)

        # Build a graph where each node has edges to nodes that differ by one character
        for word in word_set:
            for i in range(length):
                pattern = word[:i] + '*' + word[i+1:]
                word_dict[pattern].append(word)

        # BFS to find the shortest path lengths from beginWord to all other words
        queue = deque([(beginWord, [beginWord])])
        visited = {beginWord}
        min_length = float('inf')
        result = []

        while queue:
            current_word, path = queue.popleft()
            for i in range(length):
                pattern = current_word[:i] + '*' + current_word[i+1:]
                for neighbor in word_dict[pattern]:
                    if neighbor not in visited:
                        new_path = path + [neighbor]
                        if neighbor == endWord:
                            if len(new_path) < min_length:
                                min_length = len(new_path)
                                result = [new_path]
                            elif len(new_path) == min_length:
                                result.append(new_path)
                        else:
                            visited.add(neighbor)
                            queue.append((neighbor, new_path))

        return result

