        :rtype: int
        """
        stack = []
        for token in tokens:
            if token.isdigit() or (token[0] == '-' and len(token) > 1):
                stack.append(int(token))
            else:
                b = stack.pop()
                a = stack.pop()
                if token == '+':
                    stack.append(a + b)
                elif token == '-':
                    stack.append(a - b)
                elif token == '*':
                    stack.append(a * b)
                elif token == '/':
                    stack.append(int(float(a) / b))
        return stack[-1]

