class Solution(object):
    def numDecodings(self, s):
        """
        :type s: str
        :rtype: int
        """
        MOD = 10**9 + 7
        n = len(s)
        dp = [0] * (n + 1)
        dp[0] = 1
        dp[1] = 9 if s[0] == '*' else (1 if s[0] != '0' else 0)

        for i in range(1, n):
            if s[i] == '*':
                dp[i + 1] += 9 * dp[i]
                if s[i - 1] == '1':
                    dp[i + 1] += 9 * dp[i - 1]
                elif s[i - 1] == '2':
                    dp[i + 1] += 6 * dp[i - 1]
                elif s[i - 1] == '*':
                    dp[i + 1] += 15 * dp[i - 1]
            else:
                dp[i + 1] += dp[i]
                if s[i - 1] == '1':
                    dp[i + 1] += dp[i - 1]
                elif s[i - 1] == '2' and '1' <= s[i] <= '6':
                    dp[i + 1] += dp[i - 1]
                elif s[i - 1] == '*':
                    if '1' <= s[i] <= '6':
                        dp[i + 1] += 2 * dp[i - 1]
                    else:
                        dp[i + 1] += dp[i - 1]

            dp[i + 1] %= MOD

        return dp[n]

