class Solution(object):
    def strongPasswordChecker(self, password):
        """
        :type password: str
        :rtype: int
        """
        length = len(password)
        has_lower = any(c.islower() for c in password)
        has_upper = any(c.isupper() for c in password)
        has_digit = any(c.isdigit() for c in password)
        missing_type = sum(not x for x in [has_lower, has_upper, has_digit])

        if length < 6:
            return max(missing_type, 6 - length)

        if length <= 20:
            replace_count = 0
            i = 0
            while i < length:
                j = i + 1
                while j < length and password[i] == password[j]:
                    j += 1
                group_length = j - i
                if group_length >= 3:
                    replace_count += group_length // 3
                i = j
            return max(missing_type, replace_count)

        delete_count = length - 20
        replace_count = 0
        groups = []
        i = 0
        while i < length:
            j = i + 1
            while j < length and password[i] == password[j]:
                j += 1
            group_length = j - i
            if group_length >= 3:
                groups.append((group_length % 3, group_length))
            i = j

        for _ in range(delete_count):
            if not groups:
                break
            _, group_length = min(groups)
            groups.remove((group_length % 3, group_length))
            new_group_length = group_length - 1
            if new_group_length >= 3:
                groups.append((new_group_length % 3, new_group_length))

        replace_count = 0
        for remainder, group_length in groups:
            replace_count += group_length // 3

        return delete_count + max(missing_type, replace_count)

