class Solution(object):
    def findKthNumber(self, m, n, k):
        """
        :type m: int
        :type n: int
        :type k: int
        :rtype: int
        """
        def countLessEqual(mid):
            count = 0
            for i in range(1, m + 1):
                count += min(mid // i, n)
            return count

        left, right = 1, m * n
        while left < right:
            mid = (left + right) // 2
            if countLessEqual(mid) >= k:
                right = mid
            else:
                left = mid + 1
        return left

