class Solution(object):
    def simplifyPath(self, path):
        """
        :type path: str
        :rtype: str
        """
        stack = []
        for p in path.split('/'):
            if p == '' or p == '.':
                continue
            elif p == '..':
                if stack:
                    stack.pop()
            else:
                stack.append(p)
        return '/' + '/'.join(stack)

word-search-ii.solution:
from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)
        self.is_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            node = node.children[char]
        node.is_word = True

    def search_prefix(self, prefix):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

class Solution(object):
    def findWords(self, board, words):
        trie = Trie()
        for word in words:
            trie.insert(word)

        m, n = len(board), len(board[0])
        result = set()

        def dfs(i, j, node, path):
            if i < 0 or i >= m or j < 0 or j >= n or board[i][j] not in node.children:
                return

            char = board[i][j]
            next_node = node.children[char]
            new_path = path + char

            if next_node.is_word:
                result.add(new_path)

            board[i][j] = '#'  # Mark as visited
            dfs(i-1, j, next_node, new_path)
            dfs(i+1, j, next_node, new_path)
            dfs(i, j-1, next_node, new_path)
            dfs(i, j+1, next_node, new_path)
            board[i][j] = char  # Unmark

        for i in range(m):
            for j in range(n):
                prefix_node = trie.search_prefix(board[i][j])
                if prefix_node:
                    dfs(i, j, prefix_node, board[i][j])

        return list(result)

