from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)
        self.isEndOfWord = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            node = node.children[char]
        node.isEndOfWord = True

    def dfs(self, word, start, count):
        node = self.root
        for i in range(start, len(word)):
            if word[i] not in node.children:
                return False
            node = node.children[word[i]]
            if node.isEndOfWord:
                if i == len(word) - 1:
                    return count > 0
                elif self.dfs(word, i + 1, count + 1):
                    return True
        return False

    def isConcatenated(self, word):
        return self.dfs(word, 0, 0)

class Solution(object):
    def findAllConcatenatedWordsInADict(self, words):
        """
        :type words: List[str]
        :rtype: List[str]
        """
        trie = Trie()
        for word in words:
            trie.insert(word)

        result = []
        for word in words:
            if trie.isConcatenated(word):
                result.append(word)
        return result

