        """
        :type num: int
        :rtype: str
        """
        if num == 0:
            return "0"
        elif num < 0:
            return "-" + self.convertToBase7(-num)
        else:
            digits = []
            while num > 0:
                digits.append(str(num % 7))
                num //= 7
            return ''.join(digits[::-1])

