class Solution(object):
    def exist(self, board, word):
        """
        :type board: List[List[str]]
        :type word: str
        :rtype: bool
        """
        rows, cols = len(board), len(board[0])

        def dfs(r, c, i):
            if i == len(word):
                return True
            if r < 0 or c < 0 or r >= rows or c >= cols or board[r][c] != word[i]:
                return False
            temp, board[r][c] = board[r][c], '/'  # Mark as visited
            found = (dfs(r + 1, c, i + 1) or dfs(r - 1, c, i + 1) 
                      or dfs(r, c + 1, i + 1) or dfs(r, c - 1, i + 1))
            board[r][c] = temp  # Unmark
            return found

        for r in range(rows):
            for c in range(cols):
                if dfs(r, c, 0):
                    return True
        return False

third-maximum-number.solution:
class Solution(object):
    def thirdMax(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        # Use set to remove duplicates and then convert back to list
        unique_nums = list(set(nums))

        # If there are less than 3 distinct numbers, return the max
        if len(unique_nums) < 3:
            return max(unique_nums)

        # Initialize the three largest numbers with negative infinity
        first_max = second_max = third_max = float('-inf')

        # Iterate through the unique numbers to find the top three
        for num in unique_nums:
            if num > first_max:
                third_max = second_max
                second_max = first_max
                first_max = num
            elif first_max > num > second_max:
                third_max = second_max
                second_max = num
            elif second_max > num > third_max:
                third_max = num

        # Return the third maximum if it exists, otherwise return the first maximum
        return third_max if third_max != float('-inf') else first_max
